I think we only need to set only the env variables that were set by the user (`exec --env=...`, the OCI runtime will do the rest of  .  I think that this patch should be enough:

```
diff --git a/cmd/podman/exec.go b/cmd/podman/exec.go
index 1dcb88db..cc8f55f2 100644
--- a/cmd/podman/exec.go
+++ b/cmd/podman/exec.go
@@ -98,16 +98,7 @@ func execCmd(c *cli.Context) error {
                os.Exit(ret)
        }

-       // ENVIRONMENT VARIABLES
-       env := defaultEnvVariables
-       for _, e := range c.StringSlice("env") {
-               split := strings.SplitN(e, "=", 2)
-               if len(split) > 1 {
-                       env[split[0]] = split[1]
-               } else {
-                       env[split[0]] = ""
-               }
-       }
+       env := map[string]string{}

        if err := readKVStrings(env, []string{}, c.StringSlice("env")); err != nil {
                return errors.Wrapf(err, "unable to process environment variables")
```
